  1	import * as React from 'react';
  2	import { connect } from 'react-redux';
  3	import { KialiDispatch } from 'types/Redux';
  4	import {
  5	  Button,
  6	  ButtonVariant,
  7	  EmptyState,
  8	  EmptyStateBody,
  9	  EmptyStateVariant,
 10	  EmptyStateHeader
 11	} from '@patternfly/react-core';
 12	import { SortByDirection, IRow, IRowData, IAction, TableVariant, ISortBy, OnSort } from '@patternfly/react-table';
 13	import { compareNullable } from 'components/FilterList/FilterHelper';
 14	import { MetricsStats } from 'types/Metrics';
 15	import { KialiAppState } from 'store/Store';
 16	import { MetricsStatsQuery } from 'types/MetricsOptions';
 17	import { MetricsStatsThunkActions } from 'actions/MetricsStatsThunkActions';
 18	import { EnvoySpanInfo, OpenTracingHTTPInfo, OpenTracingTCPInfo, RichSpanData } from 'types/TracingInfo';
 19	import { sameSpans } from 'utils/tracing/TracingHelper';
 20	import { buildQueriesFromSpans } from 'utils/tracing/TraceStats';
 21	import { getParamsSeparator, getSpanId } from '../../../utils/SearchParamUtils';
 22	import { kialiStyle } from 'styles/StyleUtils';
 23	import { formatDuration, isErrorTag } from 'utils/tracing/TracingHelper';
 24	import { Link } from 'react-router-dom-v5-compat';
 25	import { responseFlags } from 'utils/ResponseFlags';
 26	import { renderMetricsComparison } from './StatsComparison';
 27	import { router } from 'app/History';
 28	import { isParentKiosk, kioskContextMenuAction, kioskTracingAction } from '../../Kiosk/KioskActions';
 29	import { TracingUrlProvider } from 'types/Tracing';
 30	import { KialiIcon } from 'config/KialiIcon';
 31	import { SimpleTable, SortableTh } from 'components/Table/SimpleTable';
 32	import { Theme } from '../../../types/Common';
 33	
 34	type ReduxProps = {
 35	  loadMetricsStats: (queries: MetricsStatsQuery[], isCompact: boolean) => void;
 36	};
 37	
 38	type StateProps = {
 39	  kiosk: string;
 40	  metricsStats: Map<string, MetricsStats>;
 41	  provider?: string;
 42	  theme: string;
 43	};
 44	
 45	type Props = ReduxProps &
 46	  StateProps & {
 47	    cluster?: string;
 48	    externalURLProvider?: TracingUrlProvider;
 49	    fromWaypoint: boolean; // If the traces come from a waypoint proxy
 50	    items: RichSpanData[];
 51	    namespace: string;
 52	    target: string;
 53	    traceID: string;
 54	  };
 55	
 56	interface State {
 57	  expandedSpans: Map<string, boolean>;
 58	  openKebab?: string;
 59	  sortDirection: SortByDirection;
 60	  sortIndex: number;
 61	}
 62	
 63	interface SortableCompareTh<T> extends SortableTh {
 64	  compare?: (a: T, b: T) => number;
 65	}
 66	
 67	const dangerErrorStyle = kialiStyle({
 68	  borderLeft: '3px solid var(--pf-t--global--color--status--danger--default)'
 69	});
 70	
 71	const selectedErrorStyle = kialiStyle({
 72	  borderRight: '3px solid var(--pf-t--global--color--status--info--default)',
 73	  borderLeft: '3px solid var(--pf-t--global--color--status--danger--default)'
 74	});
 75	
 76	const selectedStyle = kialiStyle({
 77	  borderRight: '3px solid var(--pf-t--global--color--status--info--default)'
 78	});
 79	
 80	const tableStyle = kialiStyle({
 81	  $nest: {
 82	    '&& tbody > tr > td': {
 83	      paddingTop: '0.25rem',
 84	      paddingBottom: '0.75rem',
 85	      $nest: {
 86	        '& .pf-v6-c-menu-toggle': {
 87	          verticalAlign: '-0.25rem'
 88	        }
 89	      }
 90	    }
 91	  }
 92	});
 93	
 94	const expandButtonStyle = kialiStyle({
 95	  padding: '0.25rem',
 96	  paddingLeft: 0
 97	});
 98	
 99	const linkIconStyle = kialiStyle({
100	  marginLeft: '0.25rem'
101	});
102	
103	const errorIconStyle = kialiStyle({
104	  marginRight: '0.25rem'
105	});
106	
107	const getClassName = (
108	  isError: boolean,
109	  isSpan,
110	  operationName,
111	  item: string,
112	  darkTheme: boolean
113	): string | undefined => {
114	  const highlight = operationName.toLowerCase().includes(item);
115	
116	  const blueColor = darkTheme ? 'var(--pf-t--color--blue--80)' : 'var(--pf-t--color--blue--10)';
117	  const highlightStyle = kialiStyle({
118	    background: blueColor
119	  });
120	
121	  const highlightErrorStyle = kialiStyle({
122	    background: blueColor,
123	    borderLeft: '3px solid var(--pf-t--global--color--status--danger--default)'
124	  });
125	  return isSpan
126	    ? isError
127	      ? selectedErrorStyle
128	      : selectedStyle
129	    : isError
130	    ? highlight
131	      ? highlightErrorStyle
132	      : dangerErrorStyle
133	    : highlight
134	    ? highlightStyle
135	    : undefined;
136	};
137	
138	const columns: SortableCompareTh<RichSpanData>[] = [
139	  {
140	    title: 'Timeline',
141	    sortable: true,
142	    compare: (a, b) => a.startTime - b.startTime
143	  },
144	  {
145	    title: 'App / Workload',
146	    sortable: true,
147	    compare: (a, b) => compareNullable(a.workload, b.workload, (a2, b2) => a2.localeCompare(b2))
148	  },
149	  {
150	    title: 'Summary',
151	    sortable: false
152	  },
153	  {
154	    title: 'Statistics',
155	    sortable: true,
156	    compare: (a, b) => a.duration - b.duration
157	  }
158	];
159	
160	class SpanTableComponent extends React.Component<Props, State> {
161	  constructor(props: Props) {
162	    super(props);
163	    const isSpan = getSpanId();
164	    const mapExpandedSpans = new Map();
165	    isSpan && mapExpandedSpans.set(isSpan, true);
166	    this.state = {
167	      expandedSpans: mapExpandedSpans,
168	      sortIndex: 0,
169	      sortDirection: SortByDirection.asc
170	    };
171	  }
172	
173	  componentDidMount(): void {
174	    this.fetchComparisonMetrics(this.props.items);
175	  }
176	
177	  componentDidUpdate(prevProps: Readonly<Props>): void {
178	    if (!sameSpans(prevProps.items, this.props.items)) {
179	      this.fetchComparisonMetrics(this.props.items);
180	    }
181	  }
182	
183	  render(): JSX.Element {
184	    const sortBy: ISortBy = { index: this.state.sortIndex, direction: this.state.sortDirection };
185	    const onSort: OnSort = (_event: React.MouseEvent, index: number, sortDirection: SortByDirection) =>
186	      this.setState({ sortIndex: index, sortDirection: sortDirection });
187	
188	    const noSpans: React.ReactNode = (
189	      <EmptyState variant={EmptyStateVariant.full}>
190	        <EmptyStateHeader titleText="No spans found" headingLevel="h5" />
191	        <EmptyStateBody>No spans match the current filters</EmptyStateBody>
192	      </EmptyState>
193	    );
194	
195	    return (
196	      <SimpleTable
197	        label="Span List"
198	        className={tableStyle}
199	        columns={columns}
200	        rows={this.rows()}
201	        emptyState={noSpans}
202	        onSort={onSort}
203	        sortBy={sortBy}
204	        actionResolver={this.actionResolver}
205	        variant={TableVariant.compact}
206	      />
207	    );
208	  }
209	
210	  private fetchComparisonMetrics(items: RichSpanData[]): void {
211	    const queries = buildQueriesFromSpans(items, false);
212	    this.props.loadMetricsStats(queries, false);
213	  }
214	
215	  private rows = (): IRow[] => {
216	    const compare = columns[this.state.sortIndex].compare;
217	    const sorted = compare
218	      ? this.props.items.sort(this.state.sortDirection === SortByDirection.asc ? compare : (a, b) => compare(b, a))
219	      : this.props.items;
220	
221	    return sorted.map(item => this.buildRow(item));
222	  };
223	
224	  private buildRow = (item: RichSpanData): IRow => {
225	    const isExpanded = this.isExpanded(item.spanID);
226	    const isSpan = item.spanID === getSpanId();
227	    const darkTheme = this.props.theme === Theme.DARK;
228	    return {
229	      cells: [
230	        <>
231	          <Button
232	            key={`${item.spanID}-duration`}
233	            className={expandButtonStyle}
234	            variant={ButtonVariant.link}
235	            onClick={() => this.toggleExpanded(item.spanID)}
236	          >
237	            {isExpanded ? <KialiIcon.AngleDown /> : <KialiIcon.AngleRight />}
238	          </Button>
239	          {formatDuration(item.relativeStartTime)}
240	        </>,
241	        this.originCell(item),
242	        this.summaryCell(item),
243	        this.statsCell(item)
244	      ],
245	      className: getClassName(item.tags.some(isErrorTag), isSpan, item.operationName, this.props.target, darkTheme),
246	      item: item
247	    };
248	  };
249	
250	  private actionResolver = (rowData: IRowData): IAction[] => {
251	    const item = rowData.item;
252	    const parentKiosk = isParentKiosk(this.props.kiosk);
253	    const appActions: IAction[] = [
254	      {
255	        isDisabled: true,
256	        title: <h1 aria-hidden="true">{`Application (${item.app})`}</h1>
257	      },
258	      {
259	        title: 'Inbound Metrics',
260	        onClick: () => {
261	          const href = `${item.linkToApp}${getParamsSeparator(rowData.item.linkToApp)}tab=in_metrics`;
262	          if (parentKiosk) {
263	            kioskContextMenuAction(href);
264	          } else {
265	            router.navigate(href);
266	          }
267	        }
268	      },
269	      {
270	        title: 'Outbound Metrics',
271	        onClick: () => {
272	          const href = `${item.linkToApp}${getParamsSeparator(rowData.item.linkToApp)}tab=out_metrics`;
273	          if (parentKiosk) {
274	            kioskContextMenuAction(href);
275	          } else {
276	            router.navigate(href);
277	          }
278	        }
279	      }
280	    ];
281	
282	    let workloadActions: IAction[] = [];
283	
284	    if (item.linkToWorkload) {
285	      workloadActions = [
286	        {
287	          isDisabled: true,
288	          title: <h1 aria-hidden="true">{`Workload (${item.workload})`}</h1>
289	        },
290	        {
291	          title: 'Logs',
292	          onClick: () => {
293	            const href = `${item.linkToWorkload}?tab=logs`;
294	            if (parentKiosk) {
295	              kioskContextMenuAction(href);
296	            } else {
297	              router.navigate(href);
298	            }
299	          }
300	        },
301	        {
302	          title: 'Inbound Metrics',
303	          onClick: () => {
304	            const href = `${item.linkToWorkload}${getParamsSeparator(rowData.item.linkToWorkload)}tab=in_metrics`;
305	            if (parentKiosk) {
306	              kioskContextMenuAction(href);
307	            } else {
308	              router.navigate(href);
309	            }
310	          }
311	        },
312	        {
313	          title: 'Outbound Metrics',
314	          onClick: () => {
315	            const href = `${item.linkToWorkload}${getParamsSeparator(rowData.item.linkToWorkload)}tab=out_metrics`;
316	            if (parentKiosk) {
317	              kioskContextMenuAction(href);
318	            } else {
319	              router.navigate(href);
320	            }
321	          }
322	        }
323	      ];
324	    }
325	
326	    let tracingActions: IAction[] = [];
327	
328	    if (this.props.externalURLProvider || parentKiosk) {
329	      const spanLink = this.props.externalURLProvider?.SpanUrl(item);
330	      tracingActions = [
331	        {
332	          isDisabled: true,
333	          title: <h1 aria-hidden="true">{`Tracing`}</h1>
334	        },
335	        {
336	          title: (
337	            <span>
338	              More span details <KialiIcon.ExternalLink className={linkIconStyle} />
339	            </span>
340	          ),
341	          onClick: e => {
342	            if (parentKiosk) {
343	              e.preventDefault();
344	              kioskTracingAction(spanLink, this.props.traceID);
345	            } else {
346	              window.open(spanLink, '_blank');
347	            }
348	          }
349	        }
350	      ];
351	    }
352	
353	    // Parent Kiosk won't have links to the app details
354	    // as most of the kubernetes consoles don't have an unified "app" entity
355	    return parentKiosk
356	      ? [...workloadActions, ...tracingActions]
357	      : [...appActions, ...workloadActions, ...tracingActions];
358	  };
359	
360	  private isExpanded = (spanID: string): boolean => {
361	    return this.state.expandedSpans.get(spanID) || false;
362	  };
363	
364	  private toggleExpanded = (spanID: string): void => {
365	    const isExpanded = this.isExpanded(spanID);
366	    this.state.expandedSpans.set(spanID, !isExpanded);
367	    this.setState({ expandedSpans: this.state.expandedSpans });
368	  };
369	
370	  private originCell = (item: RichSpanData): React.ReactNode => {
371	    const parentKiosk = isParentKiosk(this.props.kiosk);
372	    const key = `${item.spanID}-origin`;
373	    return (
374	      <>
375	        {!this.props.fromWaypoint && (
376	          <>
377	            <strong key={`${key}-app`}>Application: </strong>
378	            {(item.linkToApp &&
379	              (parentKiosk ? (
380	                <Link
381	                  key={`${key}-link-app`}
382	                  to={''}
383	                  onClick={() => {
384	                    if (item.linkToApp) {
385	                      kioskContextMenuAction(item.linkToApp);
386	                    }
387	                  }}
388	                >
389	                  {item.app}
390	                </Link>
391	              ) : (
392	                <Link key={`${key}-link-app`} to={item.linkToApp}>
393	                  {item.app}
394	                </Link>
395	              ))) ||
396	              item.app}
397	
398	            <br key={`${key}-br`} />
399	          </>
400	        )}
401	        <strong key={`${key}-wl`}>Workload: </strong>
402	        {(item.linkToWorkload &&
403	          (parentKiosk ? (
404	            <Link
405	              key={`${key}-link-wl`}
406	              to={''}
407	              onClick={() => {
408	                if (item.linkToWorkload) {
409	                  kioskContextMenuAction(item.linkToWorkload);
410	                }
411	              }}
412	            >
413	              {item.workload}
414	            </Link>
415	          ) : (
416	            <Link key={`${key}-link-wl`} to={item.linkToWorkload}>
417	              {item.workload}
418	            </Link>
419	          ))) ||
420	          'unknown'}
421	
422	        {this.isExpanded(item.spanID) && (
423	          <div key={`${key}-expanded-br-1`}>
424	            <strong key={`${key}-expanded-pod`}>Pod: </strong>
425	            {item.pod || 'unknown'}
426	          </div>
427	        )}
428	      </>
429	    );
430	  };
431	
432	  private summaryCell = (item: RichSpanData): React.ReactNode => {
433	    const flag = (item.info as EnvoySpanInfo).responseFlags;
434	    const key = `${item.spanID}-summary`;
435	
436	    return (
437	      <>
438	        {item.info.hasError && (
439	          <div key={`${key}-err`}>
440	            <KialiIcon.ExclamationCircle key={`${key}-err-ic`} className={errorIconStyle} />
441	            <strong key={`${key}-err-msg`}>This span reported an error</strong>
442	          </div>
443	        )}
444	
445	        <div key={`${key}-op`}>
446	          <strong key={`${key}-op-title`}>Operation: </strong>
447	          {flag ? (
448	            <span key={`${key}-op-name`}>
449	              {item.operationName} ({flag} <KialiIcon.ExclamationCircle key={`${key}-dan-ic`} />)
450	            </span>
451	          ) : (
452	            <span key={`${key}-op-name`}>{item.operationName}</span>
453	          )}
454	        </div>
455	
456	        <div key={`${key}-comp`}>
457	          <strong key={`${key}-comp=-title`}>Component: </strong>
458	          {item.component}
459	        </div>
460	
461	        {this.isExpanded(item.spanID) &&
462	          ((item.type === 'envoy' && this.renderEnvoySummary(item)) ||
463	            (item.type === 'http' && this.renderHTTPSummary(item)) ||
464	            (item.type === 'tcp' && this.renderTCPSummary(item)))}
465	      </>
466	    );
467	  };
468	
469	  private renderEnvoySummary = (item: RichSpanData): React.ReactNode => {
470	    const parentKiosk = isParentKiosk(this.props.kiosk);
471	    const info = item.info as EnvoySpanInfo;
472	    let rqLabel = 'Request';
473	    let peerLink: JSX.Element | undefined = undefined;
474	    const key = `${item.spanID}-summary-envoy`;
475	
476	    if (info.direction === 'inbound') {
477	      rqLabel = 'Received request';
478	
479	      if (info.peer) {
480	        peerLink = (
481	          <>
482	            {' from '}
483	            {parentKiosk ? (
484	              <Link
485	                to={''}
486	                onClick={() => {
487	                  if (info.peer) {
488	                    kioskContextMenuAction(`/namespaces/${info.peer.namespace}/workloads/${info.peer.name}`);
489	                  }
490	                }}
491	              >
492	                {info.peer.name}
493	              </Link>
494	            ) : (
495	              <Link to={`/namespaces/${info.peer.namespace}/workloads/${info.peer.name}`}>{info.peer.name}</Link>
496	            )}
497	          </>
498	        );
499	      }
500	    } else if (info.direction === 'outbound') {
501	      rqLabel = 'Sent request';
502	
503	      if (info.peer) {
504	        peerLink = (
505	          <React.Fragment key={`${key}-out`}>
506	            <span key={`${key}-out-to`}>{' to '}</span>
507	            {parentKiosk ? (
508	              <Link
509	                key={`${key}-out-link`}
510	                to={''}
511	                onClick={() => {
512	                  if (info.peer) {
513	                    kioskContextMenuAction(`/namespaces/${info.peer.namespace}/services/${info.peer.name}`);
514	                  }
515	                }}
516	              >
517	                {info.peer.name}
518	              </Link>
519	            ) : (
520	              <Link key={`${key}-out-link`} to={`/namespaces/${info.peer.namespace}/services/${info.peer.name}`}>
521	                {info.peer.name}
522	              </Link>
523	            )}
524	          </React.Fragment>
525	        );
526	      }
527	    }
528	
529	    const rsDetails: string[] = [];
530	    if (info.statusCode) {
531	      rsDetails.push(String(info.statusCode));
532	    }
533	
534	    let flagInfo: string | undefined = undefined;
535	    if (info.responseFlags) {
536	      rsDetails.push(info.responseFlags);
537	      flagInfo = responseFlags[info.responseFlags]?.help || 'Unknown flag';
538	    }
539	
540	    return (
541	      <React.Fragment key={`${key}`}>
542	        <div key={`${key}-req`}>
543	          <strong key={`${key}-req-title`}>
544	            {rqLabel}
545	            {peerLink}:{' '}
546	          </strong>
547	          <span key={`${key}-req-val`}>
548	            {info.method} {info.url}
549	          </span>
550	        </div>
551	
552	        <div key={`${key}-status`}>
553	          <strong key={`${key}-status-title`}>Response status: </strong>
554	          <span key={`${key}-status-val`}>{rsDetails.join(', ')}</span>
555	        </div>
556	        <span key={`${key}-flag`}>{flagInfo}</span>
557	      </React.Fragment>
558	    );
559	  };
560	
561	  private renderHTTPSummary = (item: RichSpanData): React.ReactNode => {
562	    const info = item.info as OpenTracingHTTPInfo;
563	    const rqLabel =
564	      info.direction === 'inbound' ? 'Received request' : info.direction === 'outbound' ? 'Sent request' : 'Request';
565	    const key = `${item.spanID}-summary-http`;
566	
567	    return (
568	      <React.Fragment key={key}>
569	        <div key={`${key}-req`}>
570	          <strong key={`${key}-req-title`}>{rqLabel}: </strong>
571	          <span key={`${key}-req-val`}>
572	            {info.method} {info.url}
573	          </span>
574	        </div>
575	
576	        {info.statusCode && (
577	          <div key={`${key}-code`}>
578	            <strong key={`${key}-code-title`}>Response status: </strong>
579	            <span key={`${key}-code-val`}>{info.statusCode}</span>
580	          </div>
581	        )}
582	      </React.Fragment>
583	    );
584	  };
585	
586	  private renderTCPSummary = (item: RichSpanData): React.ReactNode => {
587	    const info = item.info as OpenTracingTCPInfo;
588	    const key = `${item.spanID}-summary-tcp`;
589	
590	    return (
591	      <React.Fragment key={key}>
592	        {info.topic && (
593	          <div key={`${key}-topic`}>
594	            <strong key={`${key}-topic-title`}>Topic: </strong>
595	            <span key={`${key}-topic-val`}>{info.topic}</span>
596	          </div>
597	        )}
598	      </React.Fragment>
599	    );
600	  };
601	
602	  private statsCell = (item: RichSpanData): React.ReactNode => {
603	    const key = `${item.spanID}-stats`;
604	
605	    return (
606	      <div key={key}>
607	        <div key={`${key}-dur-div`}>
608	          <strong key={`${key}-dur-title`}>Duration: </strong>
609	          {formatDuration(item.duration)}
610	        </div>
611	
612	        {item.type === 'envoy' &&
613	          renderMetricsComparison(item, !this.isExpanded(item.spanID), this.props.metricsStats, () =>
614	            this.fetchComparisonMetrics([item])
615	          )}
616	      </div>
617	    );
618	  };
619	}
620	
621	const mapStateToProps = (state: KialiAppState): StateProps => ({
622	  kiosk: state.globalState.kiosk,
623	  metricsStats: state.metricsStats.data,
624	  provider: state.tracingState.info?.provider,
625	  theme: state.globalState.theme
626	});
627	
628	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxProps => ({
629	  loadMetricsStats: (queries: MetricsStatsQuery[], isCompact: boolean) =>
630	    dispatch(MetricsStatsThunkActions.load(queries, isCompact))
631	});
632	
633	export const SpanTable = connect(mapStateToProps, mapDispatchToProps)(SpanTableComponent);

